import os, sys, base64

python_dir = os.path.dirname(sys.executable)

CODE = ""

if input("Do you want to install CEPMAN? ").lower() == "y":
    print("Installing CEPMAN...")

    binary = base64.b64decode(CODE)

    try:
        with open(os.path.join(python_dir, "cepman.py"), "wb") as f:
            f.write(binary)

        with open(os.path.join(python_dir, "mgr.bat"), "w") as f:
            f.write("@echo off & .\\python.exe cepman.py %*")

    except Exception as e:
        print("Installation fault!")
        print(e)
    
    print("Done! Thank you. :)")